import akka.actor.{Actor, ActorSystem, Props}
import java.util.concurrent.atomic.AtomicReference

case class Deposit(amount: Double)
case class Withdraw(amount: Double)
case object GetBalance

class AccountActor extends Actor {
  private val balance = new AtomicReference[Double](0.0)

  def receive: Receive = {
    case Deposit(amount) =>
      balance.updateAndGet(current => current + amount)
      
    case Withdraw(amount) =>
      balance.updateAndGet { current =>
        if (current >= amount) current - amount else current
      }
      
    case GetBalance =>
      sender() ! balance.get()
  }
}

object AccountSystem extends App {
  val system = ActorSystem("AccountSystem")
  val accountActor = system.actorOf(Props[AccountActor], "accountActor")

  // Example usage
  accountActor ! Deposit(100.0)
  accountActor ! Withdraw(50.0)
  accountActor ! GetBalance
}